# -*- coding: utf-8 -*-
"""Clone-only fix: bootstrap $projects, safe tab require, resilient change_tabs, CSS underline."""
import paramiko, sys, re
sys.stdout.reconfigure(encoding="utf-8", errors="replace")

c = paramiko.SSHClient()
c.set_missing_host_key_policy(paramiko.AutoAddPolicy())
c.connect("192.168.2.203", username="root", password="hCJM3BaKYsbaSOw-F%FjQJ@Z",
          timeout=25, allow_agent=False, look_for_keys=False)
sftp = c.open_sftp()

DETAIL = "/var/www/html/bitrix/templates/vsevset_template/components/bitrix/news/client_news/bitrix/news.detail/.default"
BASE = "/var/www/html/bitrix/templates/vsevset_template"

def read(p):
    with sftp.open(p, "r") as f:
        return f.read().decode("utf-8", errors="replace")

def write(p, t):
    with sftp.open(p, "w") as f:
        f.write(t.encode("utf-8"))

# ---------- 1) init.php ----------
init_path = f"{DETAIL}/tabs/init.php"
init = read(init_path)

# Insert projects bootstrap + inline change_tabs fallback + try/catch around require
if "CLONE_BOOTSTRAP_PROJECTS" not in init:
    bootstrap = r'''
<?php
// CLONE_BOOTSTRAP_PROJECTS: needed by deal/quest/etc filters when main tab not rendered
if (!isset($projects) || !is_array($projects)) {
    $projects = array();
    if (defined('path_project')) {
        $__pr = CRMMenu::GetUserRight(path_project);
        if (($__pr['READ'] ?? 'N') != 'N') {
            $__res = CIBlockElement::GetList(
                array(),
                array('ACTIVE' => 'Y', 'IBLOCK_CODE' => SITE_ID . '_project', '=PROPERTY_CLIENT' => $arResult['ID']),
                false,
                false,
                array('ID', 'PREVIEW_PICTURE', 'DETAIL_PAGE_URL', 'NAME', 'PROPERTY_RESPONS')
            );
            while ($__el = $__res->GetNext()) {
                $projects[$__el['ID']]['ID'] = $__el['ID'];
                $projects[$__el['ID']]['NAME'] = $__el['NAME'];
                $projects[$__el['ID']]['DETAIL_PAGE_URL'] = $__el['DETAIL_PAGE_URL'];
                $projects[$__el['ID']]['PREVIEW_PICTURE'] = $__el['PREVIEW_PICTURE'];
                $projects[$__el['ID']]['RESPONS'][] = $__el['PROPERTY_RESPONS_VALUE'];
            }
        }
    }
}
?>
<script>
/* CLONE: change_tabs always available even if detail script.js failed to load */
if (typeof window.change_tabs !== 'function') {
  window.change_tabs = function (elem, tab_num) {
    try { document.querySelectorAll('#preload').forEach(function(n){n.remove();}); } catch(e) {}
    var base = window.location.pathname;
    if (tab_num) window.location.href = base + '?tab=' + encodeURIComponent(tab_num);
    else window.location.href = base;
  };
}
</script>
'''
    # Insert before the tabs HTML (after $tab_active = ...)
    marker = '$tab_active = isset( $_GET[\'tab\'] ) ? $_GET[\'tab\'] : $tab_first;\n?>'
    if marker in init:
        init = init.replace(marker, '$tab_active = isset( $_GET[\'tab\'] ) ? $_GET[\'tab\'] : $tab_first;\n?>' + bootstrap, 1)
        print("init: bootstrap inserted")
    else:
        # alternate quote style
        marker2 = '$tab_active = isset( $_GET["tab"] ) ? $_GET["tab"] : $tab_first;\n?>'
        if marker2 in init:
            init = init.replace(marker2, marker2 + bootstrap, 1)
            print("init: bootstrap inserted (alt)")
        else:
            print("INIT MARKER NOT FOUND")
            for i,l in enumerate(init.splitlines(),1):
                if 'tab_active' in l:
                    print(i, l)

# Wrap require in try/catch
old_req = """        <? // CLONE SPEED: render only active tab
        if ($tab_active == $arTab['tab']) {
            require $arTab['file'];
        }
        ?>"""
new_req = """        <? // CLONE SPEED: render only active tab (catch fatals so tabs keep working)
        if ($tab_active == $arTab['tab']) {
            try {
                require $arTab['file'];
            } catch (\\Throwable $__tab_e) {
                echo '<div style=\"padding:16px;color:#b00020;\">Ошибка вкладки: '
                    . htmlspecialchars($__tab_e->getMessage()) . '</div>';
            }
        }
        ?>"""
if old_req in init:
    init = init.replace(old_req, new_req, 1)
    print("init: try/catch around tab require")
elif "Ошибка вкладки" in init:
    print("init: try/catch already present")
else:
    print("init: require block not matched, dumping...")
    print(repr(init[-600:]))

write(init_path, init)

# ---------- 2) script.js change_tabs: debounce + clear preload ----------
js_path = f"{DETAIL}/script.js"
js = read(js_path)
old_fn = """function change_tabs(elem, tab_num) {
    // CLONE SPEED: navigate so PHP renders only active tab
    var base = window.location.pathname;
    if (tab_num) {
        window.location.href = base + '?tab=' + encodeURIComponent(tab_num);
    } else {
        window.location.href = base;
    }
}"""
new_fn = """function change_tabs(elem, tab_num) {
    // CLONE SPEED: navigate so PHP renders only active tab
    if (window.__clone_tab_nav) return;
    window.__clone_tab_nav = true;
    try {
        document.querySelectorAll('#preload').forEach(function (n) { n.remove(); });
        if (window.jQuery) { try { jQuery('#preload').remove(); jQuery('body').hide_preload(); } catch (e) {} }
    } catch (e) {}
    var base = window.location.pathname;
    var url = tab_num ? (base + '?tab=' + encodeURIComponent(tab_num)) : base;
    window.location.href = url;
}"""
if old_fn in js:
    write(js_path, js.replace(old_fn, new_fn, 1))
    print("script.js: change_tabs hardened")
elif "__clone_tab_nav" in js:
    print("script.js: already hardened")
else:
    # replace by regex
    m = re.search(r"function change_tabs\s*\([^)]*\)\s*\{.*?^\s*\}", js, re.M | re.S)
    if m and "CLONE SPEED" in m.group(0):
        write(js_path, js[:m.start()] + new_fn + js[m.end():])
        print("script.js: change_tabs replaced via regex")
    else:
        print("script.js: change_tabs pattern not found")

# ---------- 3) CSS: reliable active underline + kill stuck preload blocking clicks ----------
css_path = f"{BASE}/css/clone_layout_fix.css"
css = read(css_path)
extra = """

/* CLONE tabs: reliable active underline (runner JS is flaky after fast switches) */
.lid_detail .change_current_data .change_view,
.change_current_data.scroll .change_view {
  position: relative;
}
.lid_detail .change_current_data .change_view.active,
.change_current_data.scroll .change_view.active {
  color: #516CFE !important;
}
.lid_detail .change_current_data .change_view.active::after,
.change_current_data.scroll .change_view.active::after {
  content: '';
  position: absolute;
  left: 13px;
  right: 13px;
  bottom: 0;
  height: 4px;
  background: #516CFE;
  border-radius: 20px;
}
/* hide old runner underline to avoid double/misaligned bar */
.lid_detail .change_current_data > .runner,
.change_current_data.scroll > .runner {
  display: none !important;
}

/* never let stuck preload block tab clicks */
#preload { pointer-events: none !important; }
"""
if "reliable active underline" not in css:
    write(css_path, css + extra)
    print("css: tab underline + preload fix")
else:
    print("css: already has underline fix")

# ---------- 4) Guard deal/quest like jobs.php ----------
for rel in ["tabs/add/deal.php", "tabs/add/quest.php", "tabs/add/dogovor_list.php", "tabs/add/po_list.php"]:
    path = f"{DETAIL}/{rel}"
    try:
        t = read(path)
    except Exception as e:
        print(rel, e)
        continue
    if "CLONE_PROJECTS_GUARD" in t:
        print(rel, "already guarded")
        continue
    if "$projects" not in t:
        print(rel, "no $projects")
        continue
    # insert guard near top after first <?
    guard = "\n<? // CLONE_PROJECTS_GUARD\nif (!isset($projects) || !is_array($projects)) { $projects = array(); }\n?>\n"
    # after initial foreach tab block if present, else at start
    if t.lstrip().startswith("<?"):
        # find end of first php block or just prepend after first line
        t2 = guard + t
        write(path, t2)
        print(rel, "guard prepended")
    else:
        write(path, guard + t)
        print(rel, "guard prepended")

# same for client_f if needed
finit = f"{BASE}/components/bitrix/news/client_f_news/bitrix/news.detail/.default/tabs/init.php"
try:
    fi = read(finit)
    if "CLONE_BOOTSTRAP_PROJECTS" not in fi and "CLONE SPEED" in fi:
        # at least add $projects = array and inline change_tabs
        if "$tab_active" in fi and "change_tabs always available" not in fi:
            fi = fi.replace(
                "$tab_active = isset( $_GET['tab'] ) ? $_GET['tab'] : $tab_first;\n?>",
                "$tab_active = isset( $_GET['tab'] ) ? $_GET['tab'] : $tab_first;\n?>"
                + "\n<? if (!isset($projects) || !is_array($projects)) { $projects = array(); } ?>\n"
                + """<script>
if (typeof window.change_tabs !== 'function') {
  window.change_tabs = function (elem, tab_num) {
    var base = window.location.pathname;
    if (tab_num) window.location.href = base + '?tab=' + encodeURIComponent(tab_num);
    else window.location.href = base;
  };
}
</script>
""",
                1,
            )
            write(finit, fi)
            print("client_f init patched lightly")
except Exception as e:
    print("client_f:", e)

sftp.close()
_, o, _ = c.exec_command("php -r 'opcache_reset();' ; redis-cli FLUSHDB >/dev/null; echo ok")
print(o.read().decode())

# prod untouched check
pc = paramiko.SSHClient()
pc.set_missing_host_key_policy(paramiko.AutoAddPolicy())
pc.connect("192.168.2.16", username="root", password="pOrtkKm_123", timeout=20, allow_agent=False, look_for_keys=False)
